import type { NextConfig } from "next";

const nextConfig: NextConfig = {};

export default nextConfig;

'use server';

import { updateTag } from 'next/cache';
import { addPost } from './posts';

export async function createPost(formData: FormData) {
  const title = formData.get('title');
  const content = formData.get('content');

  if (typeof title !== 'string' || !title.trim()) {
    throw new Error('A title is required.');
  }

  if (typeof content !== 'string' || !content.trim()) {
    throw new Error('Content is required.');
  }

  addPost(title.trim(), content.trim());

  // updateTag expires the cache immediately, so the next render blocks for fresh data.
  updateTag('posts');
}
import { unstable_cache } from 'next/cache';

export type Post = {
  id: string;
  title: string;
  content: string;
  createdAt: string;
};

const posts: Post[] = [];

function readPosts() {
  return [...posts].sort((a, b) => b.createdAt.localeCompare(a.createdAt));
}

export const getPosts = unstable_cache(readPosts, ['posts'], {
  tags: ['posts']
});

export function addPost(title: string, content: string) {
  const post = {
    id: crypto.randomUUID(),
    title,
    content,
    createdAt: new Date().toISOString()
  } satisfies Post;

  posts.push(post);
  return post;
}
import { createPost } from './actions';
import { getPosts } from './posts';

export default async function Home() {
  const posts = await getPosts();

  return (
    <main>
      <h1>Posts</h1>
      <form action={createPost}>
        <label>
          Title
          <input name="title" required />
        </label>
        <label>
          Content
          <textarea name="content" required />
        </label>
        <button type="submit">Create post</button>
      </form>

      <ul>
        {posts.map((post) => (
          <li key={post.id}>
            <h2>{post.title}</h2>
            <p>{post.content}</p>
          </li>
        ))}
      </ul>
    </main>
  );
}
